#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct TreeNode {
    int val;
    struct TreeNode* left;
    struct TreeNode* right;
} TreeNode;

// Function to create a new tree node
TreeNode* createTreeNode(int val) {
    TreeNode* newNode = (TreeNode*) malloc(sizeof(TreeNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to find the path from root to a given node
void findPath(TreeNode* root, int target, int* path, int* len) {
    if (root == NULL) return;
    path[*len] = root->val;
    (*len)++;
    if (root->val == target) return;
    findPath(root->left, target, path, len);
    if (*len == 0) findPath(root->right, target, path, len);
    if (*len == 0) (*len)--;
}

// Function to print the path
void printPath(int* path, int len) {
    for (int i = 0; i < len; i++) {
        printf("%d ", path[i]);
    }
    printf("\n");
}

int main() {
    // Create the tree
    TreeNode* root = createTreeNode(3);
    root->left = createTreeNode(5);
    root->right = createTreeNode(1);
    root->left->left = createTreeNode(6);
    root->left->right = createTreeNode(2);
    root->right->left = createTreeNode(0);
    root->right->right = createTreeNode(8);
    root->left->right->left = createTreeNode(7);
    root->left->right->right = createTreeNode(4);

    int target = 7;
    int path[100];
    int len = 0;
    findPath(root, target, path, &len);
    printPath(path, len);
    return 0;
}

