        if (!root) return false;

        // Push current node to path
        arr.push(root.val);

        // If current node is the target
        if (root.val === x) return true;

        // Recurse on left and right subtrees
        if (this.getPath(root.left, arr, x) || this.getPath(root.right, arr, x)) {
