        }

        // Backtrack if not found
        arr.pop();
        return false;
    }

    // Function to return path from root to target node
    solve(root, x) {
        // Initialize result array
        const arr = [];

        // If tree is empty
        if (!root) return arr;

        // Get path using helper
        this.getPath(root, arr, x);
        return arr;
